import * as React from 'react';
import { type MetricsProps } from './Metrics';
import { forwardHTMLRef } from '../util/forwardRef';
import { resolveShorthandOld } from '../shared/slot';

type MetricsChartProps = Pick<MetricsProps, 'chart'>;

export const MetricsChart = forwardHTMLRef<MetricsChartProps, 'div'>((props, ref) => {
  const { chart } = props;
  const chartProps = resolveShorthandOld(chart);

  return <>{chart !== null && <div ref={ref}>{chartProps?.children}</div>}</>;
});
